package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP14LoginCocineroExitosoPlaywrightTest extends BaseTestPlaywright {    @Test    void loginCocineroExitoso() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']")                .fill("cocinero");        page.locator("input[name='password']")                .fill("123");        page.locator("button[type='submit']")                .click();        page.waitForLoadState();        String contenido = page.content();        assertTrue(                contenido.contains("Panel Cocinero"),                "El Panel Cocinero no se muestra después del inicio de sesión."        );        assertTrue(                contenido.contains("Pedidos Pendientes"),                "La sección Pedidos Pendientes no se muestra."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP14-login-cocinero-exitoso.png"))                        .setFullPage(true)        );    }}